module RefModule(clk, rst, count);
  input clk, rst;
  output reg [3:0] count;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, posedge rst or posedge dbg_halt) begin
    if (rst) begin
      count <= 4'b0;
    end else if (count == 4'b1001) begin
      count <= 4'b0;
    end else begin
      count <= count + 1;
    end
  end

endmodule
